// Lead Scoring Function
// Scores leads 1-100 based on enrichment signals

const lead = {
  name: $('Validate & Normalize').item.json.name,
  email: $('Validate & Normalize').item.json.email,
  company: $('Validate & Normalize').item.json.company,
  website: $('Validate & Normalize').item.json.website,
  received_at: $('Validate & Normalize').item.json.received_at
};

// Get website content (may be empty if fetch failed)
const pageContent = $input.item.json.data || $input.item.json.body || '';
const contentLower = (typeof pageContent === 'string' ? pageContent : '').toLowerCase();

let score = 30; // Base score for having valid data
const signals = [];

// Signal 1: Professional email domain (not gmail/yahoo/hotmail)
const emailDomain = lead.email.split('@')[1] || '';
const freeProviders = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'aol.com', 'icloud.com'];
if (!freeProviders.includes(emailDomain.toLowerCase())) {
  score += 15;
  signals.push('Professional email domain');
} else {
  signals.push('Free email provider (-5)');
  score -= 5;
}

// Signal 2: Website is reachable and has content
if (contentLower.length > 500) {
  score += 10;
  signals.push('Website has substantial content');
} else if (contentLower.length > 0) {
  score += 5;
  signals.push('Website reachable but minimal content');
} else {
  signals.push('Website unreachable or empty');
}

// Signal 3: Industry keywords suggesting high-value verticals
const highValueKeywords = ['saas', 'platform', 'enterprise', 'ai', 'machine learning',
  'fintech', 'healthcare', 'logistics', 'automation', 'analytics'];
const midValueKeywords = ['consulting', 'agency', 'marketing', 'services', 'solutions',
  'software', 'technology', 'digital'];

const highMatches = highValueKeywords.filter(kw => contentLower.includes(kw));
const midMatches = midValueKeywords.filter(kw => contentLower.includes(kw));

if (highMatches.length >= 2) {
  score += 20;
  signals.push(`High-value industry signals: ${highMatches.slice(0, 3).join(', ')}`);
} else if (highMatches.length === 1 || midMatches.length >= 2) {
  score += 10;
  signals.push(`Industry signals: ${[...highMatches, ...midMatches].slice(0, 3).join(', ')}`);
}

// Signal 4: Company size indicators
const sizeKeywords = ['team of', 'employees', 'offices', 'locations', 'global', 'worldwide'];
const sizeMatches = sizeKeywords.filter(kw => contentLower.includes(kw));
if (sizeMatches.length > 0) {
  score += 10;
  signals.push('Company size indicators found');
}

// Signal 5: Buying intent keywords
const intentKeywords = ['pricing', 'demo', 'free trial', 'get started', 'contact sales', 'book a call'];
const intentMatches = intentKeywords.filter(kw => contentLower.includes(kw));
if (intentMatches.length >= 2) {
  score += 10;
  signals.push('Strong buying infrastructure present');
}

// Cap score at 100
score = Math.min(100, Math.max(1, score));

// Determine lead tier
let tier;
if (score >= 70) tier = 'hot';
else if (score >= 40) tier = 'warm';
else tier = 'cold';

return {
  json: {
    ...lead,
    score,
    tier,
    signals,
    enrichment: {
      website_content_length: contentLower.length,
      email_domain: emailDomain,
      high_value_keywords: highMatches,
      mid_value_keywords: midMatches
    },
    scored_at: new Date().toISOString()
  }
};

// Log nurture lead to file for batch follow-up
const lead = $json;
const logEntry = {
  logged_at: new Date().toISOString(),
  name: lead.name,
  email: lead.email,
  company: lead.company,
  website: lead.website,
  score: lead.score,
  tier: lead.tier,
  signals: lead.signals,
  action: 'nurture_queue'
};

// In production, this would append to a database or CRM
// For this demo, we format it as a JSONL entry
return {
  json: {
    status: 'queued_for_nurture',
    lead: logEntry,
    message: `Lead ${lead.name} (${lead.company}) scored ${lead.score}/100 — added to nurture queue`
  }
};
